args.sparql:
SELECT ?game_date WHERE {
  ?game wdt:P361 wd:Q743331 .
  ?game wdt:P585 ?game_date .
  ?game wdt:P2180 ?grand_slams .
  FILTER(?grand_slams > 0)
} ORDER BY DESC(?game_date) LIMIT 1

SELECT ?game_date WHERE {
  ?game wdt:P361 wd:Q743331 .
  ?game wdt:P585 ?game_date .
  ?playerStatement ps:P652 wd:Q1340119 .
  ?game p:P168 ?playerStatement .
} ORDER BY DESC(?game_date) LIMIT 1
